/**
 * Monetization utilities — tier limits, strategy rental helpers, compute credits.
 *
 * Prices sourced from shared config/pricing.js — do NOT hardcode prices here.
 */
import { getUserTier, TIER_LEVELS } from '../hooks/useTierGate';
import {
  STRATEGY_LIMITS as _STRATEGY_LIMITS,
  ALERT_LIMITS as _ALERT_LIMITS,
  BACKTEST_LIMITS as _BACKTEST_LIMITS,
  BOT_LIMITS as _BOT_LIMITS,
  RENTAL_PRICING as _RENTAL_PRICING,
} from '../config/pricing';

// Re-export limits from shared pricing config
export const STRATEGY_LIMITS = _STRATEGY_LIMITS;
export const ALERT_LIMITS = _ALERT_LIMITS;
export const BACKTEST_LIMITS = _BACKTEST_LIMITS;
export const BOT_LIMITS = _BOT_LIMITS;

/**
 * Get the limit for a resource type for the current user.
 */
export function getTierLimit(resource) {
  const tier = getUserTier();
  const limits = {
    strategies: STRATEGY_LIMITS,
    alerts: ALERT_LIMITS,
    backtests: BACKTEST_LIMITS,
    bots: BOT_LIMITS,
  };
  const map = limits[resource];
  if (!map) return 999;
  return map[tier] ?? map.free ?? 5;
}

/**
 * Check if user's tier is at or above a required level.
 */
export function tierMeetsMin(requiredTier) {
  const userTier = getUserTier();
  return (TIER_LEVELS[userTier] ?? 0) >= (TIER_LEVELS[requiredTier] ?? 0);
}

// ── Backtest usage tracking (localStorage) ───────────────────────────────────
const BT_USAGE_KEY = 'aura_backtest_usage';

function getBacktestMonth() {
  const d = new Date();
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
}

export function getBacktestUsage() {
  try {
    const raw = localStorage.getItem(BT_USAGE_KEY);
    if (!raw) return { month: getBacktestMonth(), count: 0 };
    const data = JSON.parse(raw);
    if (data.month !== getBacktestMonth()) return { month: getBacktestMonth(), count: 0 };
    return data;
  } catch { return { month: getBacktestMonth(), count: 0 }; }
}

export function incrementBacktestUsage() {
  const usage = getBacktestUsage();
  usage.count += 1;
  localStorage.setItem(BT_USAGE_KEY, JSON.stringify(usage));
  return usage;
}

export function getBacktestRemaining() {
  const limit = getTierLimit('backtests');
  if (limit >= 999) return { used: 0, limit: Infinity, remaining: Infinity, isUnlimited: true };
  const { count } = getBacktestUsage();
  return { used: count, limit, remaining: Math.max(0, limit - count), isUnlimited: false };
}

// ── Compute credits ──────────────────────────────────────────────────────────
const CREDITS_KEY = 'aura_compute_credits';
const DEFAULT_CREDITS = { free: 5, explorer: 5, starter: 20, trader: 50, pro: 200, elite: 500, institutional: 999 };
const BACKTEST_COST = 1; // credits per backtest run

export function getComputeCredits() {
  try {
    const raw = localStorage.getItem(CREDITS_KEY);
    if (raw) return JSON.parse(raw);
    // Initialize with tier default
    const tier = getUserTier();
    const initial = DEFAULT_CREDITS[tier] ?? 5;
    const data = { remaining: initial, purchased: 0 };
    localStorage.setItem(CREDITS_KEY, JSON.stringify(data));
    return data;
  } catch { return { remaining: 5, purchased: 0 }; }
}

export function deductCredit(amount = BACKTEST_COST) {
  const credits = getComputeCredits();
  credits.remaining = Math.max(0, credits.remaining - amount);
  localStorage.setItem(CREDITS_KEY, JSON.stringify(credits));
  return credits;
}

export function addCredits(amount) {
  const credits = getComputeCredits();
  credits.remaining += amount;
  credits.purchased += amount;
  localStorage.setItem(CREDITS_KEY, JSON.stringify(credits));
  return credits;
}

// ── Strategy rental pricing (from shared config) ────────────────────────────
export const RENTAL_PRICING = _RENTAL_PRICING;

/**
 * Determine rental price for a strategy based on performance.
 * Higher win rate + profit factor = higher price.
 */
export function getStrategyRentalPrice(strategy, mode = 'signal') {
  const range = RENTAL_PRICING[mode] || RENTAL_PRICING.signal;
  const stats = strategy?.stats || strategy || {};
  const winRate = stats.avg_win_rate || stats.win_rate || 50;
  const pf = stats.profit_factor || 1;

  // Score 0-1 based on performance
  const wrScore = Math.min(1, Math.max(0, (winRate - 40) / 30)); // 40% -> 0, 70% -> 1
  const pfScore = Math.min(1, Math.max(0, (pf - 1) / 3)); // 1 -> 0, 4 -> 1
  const score = wrScore * 0.6 + pfScore * 0.4;

  const price = range.min + (range.max - range.min) * score;
  return Math.round(price * 100) / 100;
}

/**
 * Check if a strategy qualifies for "Top performing rental" badge.
 */
export function isTopPerformingRental(strategy) {
  const stats = strategy?.stats || strategy || {};
  const wr = stats.avg_win_rate || stats.win_rate || 0;
  const pf = stats.profit_factor || 0;
  const trades = stats.total_trades || stats.count || 0;
  return wr >= 60 && pf >= 2.0 && trades >= 20;
}
